import React from 'react';
import { FaGithub, FaLinkedin, FaTwitter } from 'react-icons/fa';

const Footer = () => {
  return (
    <footer className="bg-primary py-8">
      <div className="container">
        <div className="flex flex-col md:flex-row justify-between items-center">
          {/* Copyright and Contact */}
          <div className="text-textSecondary text-sm mb-4 md:mb-0 text-center md:text-left">
            © {new Date().getFullYear()} Your Name. All rights reserved.
            <div className="mt-2">
              📞 <span className="ml-1">+91-9876543210</span> <br />
              📧 <a href="mailto:your.email@example.com" className="underline hover:text-secondary">your.email@example.com</a> <br />
              {/* 🔗 <a href="https://linkedin.com/in/yourusername" target="_blank" rel="noopener noreferrer" className="underline hover:text-secondary">
                linkedin.com/in/yourusername
              </a> */}
            </div>
          </div>

          {/* Social Links with icons and text */}
          <div className="flex flex-col gap-2 text-textSecondary text-sm text-center md:text-right">
            <a
              href="https://github.com/yourusername"
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-2 hover:text-secondary transition-colors"
            >
              <FaGithub className="text-lg" />
              github.com/yourusername
            </a>
            <a
              href="https://linkedin.com/in/yourusername"
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-2 hover:text-secondary transition-colors"
            >
              <FaLinkedin className="text-lg" />
              linkedin.com/in/yourusername
            </a>
            <a
              href="https://twitter.com/yourusername"
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-2 hover:text-secondary transition-colors"
            >
              <FaTwitter className="text-lg" />
              twitter.com/yourusername
            </a>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
